def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.3:
            score = np.exp(-5 * ratio) + (0.5 - ratio)**3
        elif 0.3 <= ratio < 0.6:
            score = np.sin(ratio * np.pi) + np.log1p(ratio * 5)
        elif 0.6 <= ratio < 0.9:
            for k in range(1, 5):
                score += np.tanh(5 * (ratio - (0.6 + 0.075 * k))) / k
        else:
            score = 1 / (1 + np.exp(-15 * (ratio - 0.85)))
            if ratio > 0.95:
                score += (ratio - 0.95) * 10
        penalty = 0
        for j in range(1, 5):
            mod_val = ((item * j) % capacity)
            frac = mod_val / (capacity * j)
            if frac > 0.8:
                frac = frac ** 2
            elif 0.4 < frac <= 0.8:
                frac = np.log1p(frac * 10) / 5
            else:
                frac = frac * 2
            penalty += frac * (1 if j % 2 == 0 else -1)
        if capacity % 2 == 0 and item % 2 != 0:
            penalty *= 1.1
        elif capacity % 2 != 0 and item % 2 == 0:
            penalty *= 0.9
        priorities[i] = score + penalty
    return priorities
